// Naya customer ho ya purana, dono cases handle karo
const leadData = $('2. Normalize Lead Data').item.json;
let history = [];

try {
  const historyRow = $input.first().json;
  if (historyRow && historyRow.history_json) {
    history = JSON.parse(historyRow.history_json);
  }
} catch (e) {
  history = [];
}

const systemPrompt = {
  role: 'system',
  content: "You are a professional Dubai real estate sales consultant AI. Continue a natural qualification conversation with the customer. Ask ONE question at a time, in the language the customer is using (English, Arabic, Urdu, or Hindi). You must collect: 1) intent (buy/rent/invest), 2) preferred area (e.g. Dubai Marina, Downtown, Business Bay, Palm Jumeirah), 3) property type (apartment/villa/townhouse), 4) budget (AED), 5) timeline (30 days / 3 months / just exploring), 6) payment method (cash/mortgage). Be warm, concise, and helpful. Never invent property listings. Remember what the customer already told you earlier in this conversation and do not repeat questions they already answered. When you have enough info, say a short closing line telling the customer their consultant will follow up shortly."
};

const newUserMessage = { role: 'user', content: leadData.message };
const fullMessages = [systemPrompt, ...history, newUserMessage];

return {
  json: {
    ...leadData,
    prior_history: history,
    messages: fullMessages
  }
};

const aiReply = $json.choices[0].message.content;
const priorHistory = $('2c. Build Message Array (with Memory)').item.json.prior_history;
const leadData = $('2c. Build Message Array (with Memory)').item.json;

const updatedHistory = [
  ...priorHistory,
  { role: 'user', content: leadData.message },
  { role: 'assistant', content: aiReply }
];

// Keep only last 20 turns to avoid unlimited growth
const trimmedHistory = updatedHistory.slice(-20);

return {
  json: {
    session_id: leadData.session_id,
    history_json: JSON.stringify(trimmedHistory),
    updated_at: new Date().toISOString(),
    ai_reply_text: aiReply
  }
};

let data;
try {
  const raw = $input.first().json.choices[0].message.content;
  const cleaned = raw.replace(/```json|```/g, '').trim();
  data = JSON.parse(cleaned);
} catch (e) {
  data = { intent: 'unknown', area: 'unknown', property_type: 'unknown', budget_aed: 0, timeline: 'unknown', payment_method: 'unknown', ready_to_qualify: false };
}

let score = 0;
if (data.budget_aed >= 5000000) score += 30;
else if (data.budget_aed >= 2000000) score += 22;
else if (data.budget_aed >= 1000000) score += 15;
else if (data.budget_aed > 0) score += 8;

if (data.timeline === 'immediate') score += 30;
else if (data.timeline === '3_months') score += 15;
else if (data.timeline === 'exploring') score += 5;

if (data.payment_method === 'cash') score += 20;
else if (data.payment_method === 'mortgage') score += 12;

if (data.intent === 'buy' || data.intent === 'invest') score += 15;
else if (data.intent === 'rent') score += 8;

if (data.area !== 'unknown') score += 5;

score = Math.min(score, 100);

let tier = 'COLD';
if (score >= 70) tier = 'HOT';
else if (score >= 40) tier = 'WARM';

return {
  json: {
    ...$('2. Normalize Lead Data').item.json,
    ...data,
    lead_score: score,
    lead_tier: tier,
    timestamp: new Date().toISOString()
  }
};

